// Schema + digest -> `export type Input` text (design §4.3/§4.4, ADR-0027 Gap-4 emission
// table). Escaping is not optional (SEC-1): every schema-derived string reaches the
// generated .ts ONLY through JSON.stringify (string-literal / property-key positions),
// and a label destined for a JSDoc comment has the `*/` breakout sequence guarded. The
// generated file is TYPE-ONLY (ADR-0031) — it produces zero runtime JS — but the escaping
// discipline still holds so a hostile schema can never distort the emitted TEXT into
// something a human misreads or a downstream tool mis-tokenizes.

import type { Schema, SchemaProperty } from "../src/core/schema/schema-model.ts";
import { RECOGNIZED_KINDS } from "../src/core/schema/schema-sufficiency.ts";

export const GENERATED_HEADER =
  "// AUTO-GENERATED by pbuilder-codegen — do not edit. Regenerate: pbuilder-codegen <package-dir>";

const IDENTIFIER_RE = /^[A-Za-z_$][\w$]*$/;

// schema-parse.ts casts `type` to `SchemaKind` with zero runtime validation (`value.type as
// SchemaKind`), so a hostile schema.json can hand this function ANY string at runtime despite
// the compile-time type saying otherwise. This is the last line of defence before emit: never
// trust the narrowing, always allow-list against the canonical recognized-kind set (also the
// checkSufficiency hard-fail set — generateSchema's belt-and-suspenders gate is the primary
// defence; this is the backstop if that gate is ever bypassed or its call site removed).
export class UnrecognizedPropertyTypeError extends Error {
  readonly field: string;

  constructor(field: string) {
    super(`unrecognized property type for "${field}"`);
    this.name = "UnrecognizedPropertyTypeError";
    this.field = field;
  }
}

function emitPropertyKey(key: string): string {
  return IDENTIFIER_RE.test(key) ? key : JSON.stringify(key);
}

// Fixed vocabulary (string/number/boolean) is never schema-derived text; only the enum
// choices are — each goes through JSON.stringify individually (SEC-1). Anything outside the
// recognized-kind allow-list is refused rather than emitted verbatim (SEC-1/TFO-01) — a
// non-`SchemaKind` string reaching here is real top-level text bound for the generated .ts.
function emitPropertyType(property: SchemaProperty): string {
  if (property.type === "enum") {
    const choices = property.choices ?? [];
    return choices.map((choice) => JSON.stringify(choice)).join(" | ");
  }
  if (!RECOGNIZED_KINDS.has(property.type)) {
    throw new UnrecognizedPropertyTypeError(property.key);
  }
  return property.type;
}

// Guards the `*/` comment-breakout sequence and strips newlines (keeps the doc comment a
// single, well-formed line regardless of hostile input) — labels are prose, not code, so
// they are escaped for the comment position rather than JSON.stringify'd.
function sanitizeLabelForComment(label: string): string {
  return label.replace(/\*\//g, "*\\/").replace(/[\r\n]+/g, " ");
}

function emitProperty(property: SchemaProperty): string {
  const key = emitPropertyKey(property.key);
  const optional = property.required === false ? "?" : "";
  const type = emitPropertyType(property);
  const doc = property.label !== undefined
    ? `  /** ${sanitizeLabelForComment(property.label)} */\n`
    : "";
  return `${doc}  ${key}${optional}: ${type};`;
}

export function emitInputType(schema: Schema, digest: string): string {
  const members = schema.properties.map(emitProperty).join("\n");
  return [
    GENERATED_HEADER,
    `// @schema-digest sha256:${digest}`,
    "",
    "export type Input = {",
    members,
    "};",
    "",
  ].join("\n");
}
